// =====================================================
// KI-BREMSE v2.6 – Context Packager Output + Burst Pacing + Ref Query + Needs/Objection Detection
// IMPROVED: Robust THEM/YOU normalization with 10-path fallback chain
// Input erwartet (alle Varianten werden abgefangen):
//  - live_context.you / live_context.them  (primary)
//  - live_context.you_text / live_context.them_text
//  - live_context.agent / live_context.customer / live_context.customer_text
//  - $json.you / $json.them / $json.you_text / $json.them_text (top-level)
//  - $json.agent / $json.customer / $json.agent_text / $json.customer_text
//  - $json.context.you / $json.context.them (nested context)
//  - live_context.talk_ratio_pct_you / talk_ratio_pct_them
//  - live_context.duration_sec
//  - memory_context.customer / topics
// =====================================================

const staticData = $getWorkflowStaticData("global");

// -----------------------------
// CONFIG
// -----------------------------
const MIN_WPM_WINDOW_SEC = 15;
const STABLE_MAX_SEC = 60;
const BURST_MIN_SEC = 10;
const BURST_MAX_SEC = 25;

const DOMINANCE_WINDOW_N = 8;
const DOM_YOU = 60;
const DOM_THEM = 40;

const PACE_FAST_WPM = 170;
const PACE_SLOW_WPM = 70;

// -----------------------------
// INPUT
// -----------------------------
const live = $json.live_context || {};
const mem = $json.memory_context || {};
const ctx = $json.context || {}; // Dritter Container: falls n8n node context abflacht

function firstNonEmpty(...vals) {
  for (const v of vals) {
    if (v !== null && v !== undefined) {
      const s = String(v).trim();
      if (s) return s;
    }
  }
  return "";
}

function safeNode(pathFn) {
  try { return pathFn(); } catch (_) { return null; }
}

const session_id = firstNonEmpty(
  $json.session_id,
  live.session_id,
  mem.session_id
) || null;

const lead_id = firstNonEmpty(
  $json.lead_id,
  live.lead_id,
  mem.lead_id,
  safeNode(() => $('Webhook2').first().json.body.ID),
  safeNode(() => $('Get row(s)1').first().json.lead_id),
  safeNode(() => $('Get row(s)1').first().json.id)
) || 'unknown_lead';

// =====================================================
// NORMALISIERUNG v2.5 – Robuste THEM/YOU Fallback-Kette
// Reihenfolge: live_context (primär) → top-level → ctx-nested
// =====================================================
const _raw_them = firstNonEmpty(
  live.them,
  live.them_text,
  live.customer,
  live.customer_text,
  $json.them,
  $json.them_text,
  $json.customer,
  $json.customer_text,
  ctx.them,
  ctx.customer
);

const _raw_you = firstNonEmpty(
  live.you,
  live.you_text,
  live.agent,
  live.agent_text,
  $json.you,
  $json.you_text,
  $json.agent,
  $json.agent_text,
  ctx.you,
  ctx.agent
);

const liveThemText = _raw_them;
const liveYouText  = _raw_you;

// Debug: welcher Pfad hat THEM gezogen?
function resolveSource(candidates, labels) {
  for (let i = 0; i < candidates.length; i++) {
    const v = candidates[i];
    if (v !== null && v !== undefined && String(v).trim()) return labels[i];
  }
  return "none";
}
const debug_them_source = resolveSource(
  [live.them, live.them_text, live.customer, live.customer_text,
   $json.them, $json.them_text, $json.customer, $json.customer_text,
   ctx.them, ctx.customer],
  ["live.them","live.them_text","live.customer","live.customer_text",
   "$json.them","$json.them_text","$json.customer","$json.customer_text",
   "ctx.them","ctx.customer"]
);
const debug_you_source = resolveSource(
  [live.you, live.you_text, live.agent, live.agent_text,
   $json.you, $json.you_text, $json.agent, $json.agent_text,
   ctx.you, ctx.agent],
  ["live.you","live.you_text","live.agent","live.agent_text",
   "$json.you","$json.you_text","$json.agent","$json.agent_text",
   "ctx.you","ctx.agent"]
);

// Guardrail: gab es upstream THEM-Daten, die aber nicht ankamen?
const upstream_them_present = !!(
  live.them || live.them_text || live.customer || live.customer_text ||
  $json.them || $json.them_text || $json.customer || $json.customer_text ||
  ctx.them || ctx.customer
);
const ki_bremse_warnings = [];
if (!liveThemText && upstream_them_present) {
  ki_bremse_warnings.push("them_lost_despite_upstream_data");
} else if (!liveThemText) {
  ki_bremse_warnings.push("them_empty_no_upstream");
}

const talk_you_raw = live.talk_ratio_pct_you;
const talk_them_raw = live.talk_ratio_pct_them;

const memory_topics = Array.isArray(mem.topics) ? mem.topics : [];
const memory_context_text = String(mem.customer || "").trim();

// =====================================================
// MEMORY FALLBACK für THEM (v2.5)
// Wenn live THEM leer → letzten bekannten Kundenspeech aus
// memory_context.customer als Kontext-Ersatz verwenden.
// Nur die letzten ~200 Zeichen (aktuellster Teil).
// Markierung "[Memory]" damit AI und Parser wissen: kein Live-Transkript.
// =====================================================
let liveThemTextFinal = liveThemText;
let them_source_final = debug_them_source;
if (!liveThemText && memory_context_text) {
  const memSnippet = memory_context_text.slice(-200).replace(/^\s*\w+:?\s*/, "").trim();
  liveThemTextFinal = `[Memory] ${memSnippet}`;
  them_source_final = "memory_context.customer_fallback";
  ki_bremse_warnings.push("them_from_memory_fallback");
}

// duration clamp
let duration_sec = Number(live.duration_sec ?? 0);
if (!Number.isFinite(duration_sec) || duration_sec <= 0) duration_sec = 60;
duration_sec = Math.max(5, Math.min(120, duration_sec));

// stable/burst windows
const stableDurationSec = Math.min(STABLE_MAX_SEC, Math.max(MIN_WPM_WINDOW_SEC, duration_sec));
const burstDurationSec = Math.min(BURST_MAX_SEC, Math.max(BURST_MIN_SEC, duration_sec));
// -----------------------------
// HELPERS
// -----------------------------
function countWords(text) {
  if (!text) return 0;
  return text.trim().split(/\s+/).filter(Boolean).length;
}

function pacingStatusFromWpm(wpm) {
  if (!wpm || wpm <= 0) return "n/a";
  if (wpm > PACE_FAST_WPM) return "too_fast";
  if (wpm < PACE_SLOW_WPM) return "too_slow";
  return "ok";
}

function clip(s, n) {
  s = String(s || "").replace(/\s+/g, " ").trim();
  if (!s) return "";
  return s.length > n ? s.slice(0, n) : s;
}

// -----------------------------
// WORDS
// -----------------------------
const words_you = countWords(liveYouText);
const words_them = countWords(liveThemText);

// -----------------------------
// WPM (Stable + Burst)
// -----------------------------
const wpm_you = Math.round((words_you / stableDurationSec) * 60);
const wpm_them = Math.round((words_them / stableDurationSec) * 60);

const wpm_burst_you = Math.round((words_you / burstDurationSec) * 60);
const wpm_burst_them = Math.round((words_them / burstDurationSec) * 60);

const pacing_you = pacingStatusFromWpm(wpm_burst_you);
const pacing_them = pacingStatusFromWpm(wpm_burst_them);

// -----------------------------
// TALK RATIO (prefer live metrics)
// -----------------------------
let talk_ratio_pct_you = (typeof talk_you_raw === "number") ? talk_you_raw : null;
let talk_ratio_pct_them = (typeof talk_them_raw === "number") ? talk_them_raw : null;

if (talk_ratio_pct_you === null || talk_ratio_pct_them === null) {
  const total = words_you + words_them;
  talk_ratio_pct_you = total > 0 ? Math.round((words_you / total) * 100) : 0;
  talk_ratio_pct_them = total > 0 ? 100 - talk_ratio_pct_you : 0;
}

talk_ratio_pct_you = Math.max(0, Math.min(100, talk_ratio_pct_you));
talk_ratio_pct_them = Math.max(0, Math.min(100, talk_ratio_pct_them));

// -----------------------------
// DOMINANCE (rolling avg)
// -----------------------------
if (!Array.isArray(staticData.talk_ratio_memory)) staticData.talk_ratio_memory = [];
staticData.talk_ratio_memory.push(talk_ratio_pct_you);
staticData.talk_ratio_memory = staticData.talk_ratio_memory.slice(-DOMINANCE_WINDOW_N);

const avg_you = Math.round(
  staticData.talk_ratio_memory.reduce((a,b) => a + b, 0) / staticData.talk_ratio_memory.length
);

let dominates = "balanced";
if (avg_you > DOM_YOU) dominates = "you";
else if (avg_you < DOM_THEM) dominates = "them";

// -----------------------------
// WARNINGS
// -----------------------------
const burst_warning = (wpm_burst_you > PACE_FAST_WPM);
const pacing_warning = (pacing_you === "too_fast") || burst_warning;
const talk_ratio_warning = (dominates === "you") || (talk_ratio_pct_you > 55);

// -----------------------------
// CONTEXT for AI
// Kein .trim() — Zeilenstruktur THEM:/YOU: muss immer erhalten bleiben.
// Overlay-Regex: ^(THEM|YOU)\s*:\s*(.*)$  — exakte Schreibweise zwingend.
// -----------------------------
const live_context_text = `THEM: ${liveThemTextFinal}\nYOU: ${liveYouText}`;

