function detectSalesPhase(youText, themText, memText, trPctYou, wordsYou, wordsThemVal) {
  const youLow  = (youText  || "").toLowerCase();
  const themLow = (themText || "").toLowerCase();
  const memLow  = (memText  || "").slice(0, 600).toLowerCase();
  const totalW  = (wordsYou || 0) + (wordsThemVal || 0);

  const scores = { begruessung: 0, bedarfsanalyse: 0, pitch: 0, einwandbehandlung: 0, followup: 0 };

  // BEGRÜSSUNG
  if (/\b(hallo|guten tag|guten morgen|guten abend|mein name ist|ich bin .{0,20} von|wie geht|freut mich|schön dass|danke für .{0,10} zeit)\b/.test(youLow)) scores.begruessung += 3;
  if (totalW < 120) scores.begruessung += 2;
  if (totalW < 60)  scores.begruessung += 3;
  if (!youLow.includes("angebot") && !youLow.includes("lösung") && !youLow.includes("schicke")) scores.begruessung += 1;

  // BEDARFSANALYSE
  const bedarfYou = ["was sind", "was ist ihr", "welche herausforderung", "wie läuft", "wie handhaben sie", "was brauchen sie", "was fehlt", "was wünschen sie", "erzählen sie", "was hat bisher", "wie viele", "wo sehen sie", "was ist ihnen wichtig", "wie machen sie das aktuell", "können sie mir mehr"];
  const bedarfThem = ["wir haben aktuell", "im moment", "gerade kämpfen", "unser problem", "wir suchen", "uns fehlt", "ich wünsche", "wir wollen eigentlich", "das fehlt uns"];
  bedarfYou.forEach(k => { if (youLow.includes(k))  scores.bedarfsanalyse += 2; });
  bedarfThem.forEach(k => { if (themLow.includes(k)) scores.bedarfsanalyse += 1; });
  if ((youLow.match(/\?/g) || []).length >= 2) scores.bedarfsanalyse += 2;
  if (trPctYou !== null && Number(trPctYou) < 45) scores.bedarfsanalyse += 2;

  // PITCH
  const pitchYou = ["ich würde gerne zeigen", "wir bieten", "unser angebot", "unsere lösung", "das bedeutet für sie", "konkret bedeutet", "stellen sie sich vor", "typischerweise", "in der praxis", "wir machen das", "bei uns funktioniert", "wir arbeiten mit", "ich zeige ihnen", "ich erkläre kurz", "was das für sie heißt"];
  pitchYou.forEach(k => { if (youLow.includes(k)) scores.pitch += 2; });
  if (trPctYou !== null && Number(trPctYou) > 62) scores.pitch += 2;

  // EINWANDBEHANDLUNG — starke Trigger aus THEM
  const einwandThem = ["zu teuer", "kein budget", "kein interesse", "keine zeit", "muss ich noch", "müssen wir noch", "überlegen", "weiß nicht", "bin nicht sicher", "passt nicht", "haben das intern", "machen wir selbst", "brauchen wir nicht", "aktuell nicht", "gerade kein bedarf"];
  const einwandYou  = ["ich verstehe", "das ist verständlich", "viele unserer kunden", "was wäre wenn wir", "was müsste passieren", "darf ich kurz fragen", "andere kunden hatten"];
  einwandThem.forEach(k => { if (themLow.includes(k)) scores.einwandbehandlung += 4; }); // Hard trigger
  einwandYou.forEach(k =>  { if (youLow.includes(k))  scores.einwandbehandlung += 2; });

  // FOLLOW UP
  const followupYou = ["nächster schritt", "ich schicke ihnen", "ich sende", "angebot schicken", "ich bereite vor", "wann passt es ihnen", "können wir einen termin", "ich melde mich", "wir sprechen", "auf was können wir uns", "können wir das festhalten", "bis wann", "bis dann", "bis nächste"];
  followupYou.forEach(k => { if (youLow.includes(k)) scores.followup += 2; });
  if (memLow.includes("nächster schritt") || memLow.includes("termin")) scores.followup += 1;

  // Winner
  const entries = Object.entries(scores).sort((a, b) => b[1] - a[1]);
  const [winPhase, winScore] = entries[0];
  const total = entries.reduce((s, [, v]) => s + v, 0);
  const confidence = total > 0 ? Math.min(0.95, winScore / total) : 0;

  if (winScore < 2) return { phase: "bedarfsanalyse", confidence: 0.25, scores };
  return { phase: winPhase, confidence: Math.round(confidence * 100) / 100, scores };
}

