  const priorityOrder = ["budget_preis", "entscheider", "timing", "kein_bedarf", "skepsis", "konkurrenz"];

  for (const key of priorityOrder) {
    const pattern = OBJECTION_PATTERNS[key];
    for (const kw of pattern.keywords) {
      if (text.includes(kw)) {
        const sentences = themText.split(/[.!?\n]+/);
        const matchSentence = sentences.find(s => s.toLowerCase().includes(kw)) || "";
        return {
          type:            key,
          label:           pattern.label,
          icon:            pattern.icon,
          quote:           matchSentence.trim().slice(0, 150),
          keyword_matched: kw,
          confidence:      0.85
        };
      }
    }
  }
  return null;
}

const phaseResult = detectSalesPhase(
  liveYouText, liveThemText, memory_context_text,
  talk_ratio_pct_you, words_you, words_them
);
const script_phase            = phaseResult.phase;
const script_phase_confidence = phaseResult.confidence;
const script_phase_scores     = phaseResult.scores;

// =====================================================
// NEEDS + OBJECTION – Detection + Session Accumulation
// =====================================================

// Needs: detect from current THEM text (keyword layer)
const detected_needs_keywords = detectNeeds(liveThemText, memory_context_text);

// Session-level accumulation (persists across multiple KI-Bremse calls within same session)
if (!Array.isArray(staticData.session_detected_needs)) staticData.session_detected_needs = [];
if (staticData.session_id_needs !== session_id) {
  // New session — reset accumulated needs
  staticData.session_detected_needs = [];
  staticData.session_id_needs = session_id;
}
for (const need of detected_needs_keywords) {
  const existing = staticData.session_detected_needs.find(n => n.key === need.key);
  if (!existing) {
    staticData.session_detected_needs.push(need);
  } else if (need.quote && need.quote.length > 4) {
    existing.quote = need.quote; // update with fresher quote
  }
}
const detected_needs_session = staticData.session_detected_needs.slice(); // full session-accumulated needs

// Objection: detect from current THEM text only (no accumulation — only current moment)
const active_objection = detectObjection(liveThemText);

// Fastlane trigger flag: objection detected → override normal routing
const objection_fastlane_trigger = active_objection !== null && active_objection.confidence >= 0.7;

// -----------------------------
// OUTPUT
// -----------------------------
return [{
  json: {
    session_id,
    lead_id,
    generated_at: new Date().toISOString(),
    new_run: true,

    // References: Query + Filter Kandidaten
    reference_query,
    ref_context,
    reference_filter_candidates,

    // Branche für Filter (VERBESSERT)
    branche_candidates,
    branche_hint_text,
    branche_confidence,
    branche_scores,

    // Branchen Fallbacks
    campaign_type,
    reference_branche_primary,
    reference_branche_fallbacks,

    // Agent Inputs
    live_context_text,
    memory_context_text,
    memory_topics,

    // Words
    words_you,
    words_them,

    // WPM stable + burst
    wpm_you,
    wpm_them,
    wpm_burst_you,
    wpm_burst_them,

    // pacing
    pacing_you,
    pacing_them,

    // Backwards compat
    current_wpm: wpm_you,
    pacing_status: pacing_you,

    // Talk ratio
    talk_ratio_pct_you,
    talk_ratio_pct_them,

    // Memory scoring
    dominates,
    avg_talk_ratio_you: avg_you,

    // Warnings
    pacing_warning,
    talk_ratio_warning,
    burst_warning,

    // Durations
    duration_sec,
    stable_duration_sec: stableDurationSec,
    burst_duration_sec: burstDurationSec,

    // v2.5 – Normalisierungs-Debug (immer mitgeschickt)
    ki_bremse_warnings,
    debug_them_source: them_source_final,
    debug_you_source,
    debug_live_context_built: true,

    // Sales Phase Detection
    script_phase,
    script_phase_confidence,
    script_phase_scores,

    // Needs + Objection Detection
    detected_needs_keywords,
    detected_needs_session,
    active_objection,
    objection_fastlane_trigger
  }
}];

const text = $json.text || "";

// Liste der Müll-Sätze
const junkPhrases = [
