parameters.jsCode:
// ================================
// Context Builder (robust, live + replay)
// ================================

const WINDOW_SEC = 90;

// 1️⃣ Alle gültigen Timestamps sammeln
const allTs = items
  .map(i => Number(i.json?.ts))
  .filter(ts => Number.isFinite(ts));

if (!allTs.length) {
  return [{
    json: {
      session_id: "unknown-session",
      context_you: "",
      context_them: "",
      words_you: 0,
      words_them: 0,
      talk_ratio_pct_you: 0,
      talk_ratio_pct_them: 0,
      duration_sec: WINDOW_SEC,
      generated_at: new Date().toISOString(),
      debug: "no_ts_found"
    }
  }];
}

// 2️⃣ Referenz-Zeit = neuester Transcript-Timestamp
const maxTs = Math.max(...allTs);
const windowFrom = maxTs - WINDOW_SEC * 1000;

// Container
let sessionId = null;
let youTexts = [];
let themTexts = [];
let wordsYou = 0;
let wordsThem = 0;
let minTs = null;
let usedMaxTs = null;

// Wortzähler
function countWords(t) {
  return t ? t.trim().split(/\s+/).filter(Boolean).length : 0;
}

// 3️⃣ Iteration
for (const item of items) {
  const j = item.json || {};
  const ts = Number(j.ts);

  if (!Number.isFinite(ts) || ts < windowFrom) continue;

  if (!sessionId && j.session_id) sessionId = j.session_id;

  const text = (j.text || "").trim();
  if (!text) continue;

  const src = (j.source || "").toLowerCase();

  let speaker = null;
  if (src === "you" || src === "y") speaker = "you";
  if (src === "customer" || src === "them") speaker = "them";
  if (!speaker) continue;

  minTs = minTs === null ? ts : Math.min(minTs, ts);
  usedMaxTs = usedMaxTs === null ? ts : Math.max(usedMaxTs, ts);

  const wc = countWords(text);

  if (speaker === "you") {
    youTexts.push(text);
    wordsYou += wc;
  } else {
    themTexts.push(text);
    wordsThem += wc;
  }
}

// 4️⃣ Dauer
let durationSec = WINDOW_SEC;
if (minTs && usedMaxTs && usedMaxTs > minTs) {
  durationSec = Math.max(5, Math.round((usedMaxTs - minTs) / 1000));
}

// 5️⃣ Talk Ratio
const totalWords = wordsYou + wordsThem;
const pctYou = totalWords ? Math.round((wordsYou / totalWords) * 100) : 0;
const pctThem = totalWords ? 100 - pctYou : 0;

// 6️⃣ Output
return [{
  json: {
    session_id: sessionId || "unknown-session",

    context_you: youTexts.join(" ").trim(),
    context_them: themTexts.join(" ").trim(),

    words_you: wordsYou,
    words_them: wordsThem,

    talk_ratio_pct_you: pctYou,
    talk_ratio_pct_them: pctThem,

    duration_sec: durationSec,
    generated_at: new Date().toISOString(),

    debug_window_from: windowFrom,
    debug_window_to: maxTs
  }
}];

// ===============================
// Conversation Memory Builder v1.2
// Robust (live + replay) + Fallback
// ===============================

const WINDOW_MINUTES = 15;
const MAX_CHARS = 1200;
const FALLBACK_LAST_CUSTOMER_TURNS = 8; // wenn im Window nichts ist

const all = $input.all();
if (!all.length) {
  return [{
    json: {
      session_id: null,
      conversation_context: "",
      customer_topics: [],
      turns_customer: 0,
      duration_sec: WINDOW_MINUTES * 60,
      generated_at: new Date().toISOString(),
      reason: "no_items"
    }
  }];
}

const sessionId =
  all.find(i => i.json.session_id)?.json.session_id || "unknown-session";

function toMs(ts) {
  if (ts === null || ts === undefined) return null;
  if (typeof ts === "number") return ts;
  const p = Date.parse(String(ts));
  return Number.isNaN(p) ? null : p;
}

function isCustomer(src) {
  const s = String(src || "").toLowerCase();
  return s === "customer" || s === "them";
}

const rows = all
  .map(i => i.json)
  .map(t => ({ ...t, ts_ms: toMs(t.ts) }))
  .filter(t => t.ts_ms !== null)
  .sort((a, b) => a.ts_ms - b.ts_ms);

if (!rows.length) {
  return [{
    json: {
      session_id: sessionId,
      conversation_context: "",
      customer_topics: [],
      turns_customer: 0,
      duration_sec: WINDOW_MINUTES * 60,
      generated_at: new Date().toISOString(),
      reason: "no_ts_found"
    }
  }];
}

// Referenz = neuester ts
const maxTs = rows[rows.length - 1].ts_ms;
const windowFrom = maxTs - WINDOW_MINUTES * 60 * 1000;

// Customer turns im Window
let customerTurns = rows
  .filter(t =>
    t.ts_ms >= windowFrom &&
    isCustomer(t.source) &&
    typeof t.text === "string" &&
    t.text.trim().length > 3
  );

// Fallback: letzte N customer turns aus der gesamten Session
let usedFallback = false;
if (!customerTurns.length) {
  const allCustomer = rows.filter(t =>
    isCustomer(t.source) &&
    typeof t.text === "string" &&
    t.text.trim().length > 3
  );
  if (allCustomer.length) {
    usedFallback = true;
    customerTurns = allCustomer.slice(-FALLBACK_LAST_CUSTOMER_TURNS);
  }
}

if (!customerTurns.length) {
  return [{
    json: {
      session_id: sessionId,
      conversation_context: "",
      customer_topics: [],
      turns_customer: 0,
      duration_sec: WINDOW_MINUTES * 60,
      generated_at: new Date().toISOString(),
      reason: "no_customer_available",
      debug_window_from: windowFrom,
      debug_window_to: maxTs
    }
  }];
}

// Kontext
let contextText = customerTurns
  .map(t => t.text.trim())
  .join(" ")
  .replace(/\s+/g, " ")
  .trim();

// Kürzen von hinten
if (contextText.length > MAX_CHARS) {
  contextText = contextText.slice(-MAX_CHARS);
}

// Topics
const keywords = {};
contextText
  .toLowerCase()
  .replace(/[^a-zäöüß\s]/gi, "")
  .split(/\s+/)
  .filter(w => w.length > 4)
  .forEach(w => { keywords[w] = (keywords[w] || 0) + 1; });

const topTopics = Object.entries(keywords)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 5)
  .map(([w]) => w);

return [{
  json: {
    session_id: sessionId,
    conversation_context: contextText,
    customer_topics: topTopics,
    turns_customer: customerTurns.length,
    duration_sec: WINDOW_MINUTES * 60,
    generated_at: new Date().toISOString(),
    used_fallback: usedFallback,
    debug_window_from: windowFrom,
    debug_window_to: maxTs
  }
}];

// ===============================
  // Context Packager (Live + Memory + Last Tip)
  // Run once for all items
  // ===============================

  const MAX_LIVE_CHARS = 900;
  const MAX_MEMORY_CHARS = 900;

  const all = $input.all().map(i => i.json);

  // Wir erwarten i.d.R. 2 Items: Live Context Builder + Memory Builder
  const live = all.find(x => x.context_you !== undefined || x.context_them !== undefined) || {};
  const mem  = all.find(x => x.conversation_context !== undefined) || {};

  function clipTail(s, max) {
    s = String(s || "").trim();
    if (s.length <= max) return s;
    return s.slice(-max);
  }

  function firstNonEmpty(...vals) {
    for (const v of vals) {
      if (v !== null && v !== undefined) {
        const s = String(v).trim();
        if (s) return s;
      }
    }
    return "";
  }

  function safeNode(pathFn) {
    try { return pathFn(); } catch (_) { return null; }
  }

  // Live (YOU/THEM)
  const liveYou  = clipTail(live.context_you || "", Math.floor(MAX_LIVE_CHARS * 0.55));
  const liveThem = clipTail(live.context_them || "", Math.floor(MAX_LIVE_CHARS * 0.45));

  // Memory (Customer)
  const memoryCustomer = clipTail(mem.conversation_context || "", MAX_MEMORY_CHARS);

  // -----------------------------
  // Lead / Session robust bestimmen
  // -----------------------------
  const leadIdFromInputs = all
    .map(x =>
      firstNonEmpty(
        x.lead_id,
        x.leadId,
        x.live_context?.lead_id,
        x.memory_context?.lead_id,
        x.customer?.lead_id,
        x.lead?.id
      )
    )
    .find(Boolean);

  const sessionIdFromInputs = all
    .map(x =>
      firstNonEmpty(
        x.session_id,
        x.sessionId,
        x.live_context?.session_id,
        x.memory_context?.session_id
      )
    )
    .find(Boolean);

   const lead_id = firstNonEmpty(
    safeNode(() => $('Webhook GET Endpoint für Overlay1').first().json.query.lead_id),
    live.lead_id,
    mem.lead_id,
    leadIdFromInputs,
    safeNode(() => $('Webhook2').first().json.body.ID),
    safeNode(() => $('Get row(s)1').first().json.lead_id),
    safeNode(() => $('Get row(s)1').first().json.id)
  ) || "unknown_lead";

  const session_id = firstNonEmpty(
    live.session_id,
    mem.session_id,
    sessionIdFromInputs
  ) || "unknown-session";

  // -----------------------------
  // ✅ Last Tip aus globalem Cache holen
  // -----------------------------
  const staticData = $getWorkflowStaticData('global');
  const last = staticData.lastTipObj || {};

  const last_tip = last.tip || "";
  const last_tip_type = last.tip_type || "general";
  const last_tip_at = last.generated_at || "";
  const last_tip_hint = last_tip ? String(last_tip).slice(0, 160) : "";

  // -----------------------------
  // Output
  // -----------------------------
  return [{
    json: {
      session_id,
      lead_id,

      // Live Context
      live_context: {
        you: liveYou,
        them: liveThem,
        talk_ratio_pct_you: live.talk_ratio_pct_you ?? null,
        talk_ratio_pct_them: live.talk_ratio_pct_them ?? null,
        duration_sec: live.duration_sec ?? null
      },

      // Memory Context
      memory_context: {
        customer: memoryCustomer,
        topics: mem.customer_topics || [],
        turns_customer: mem.turns_customer ?? 0,
        used_fallback: !!mem.used_fallback
      },

      // Last Tip (für Eskalation / Anti-Repeat)
      last_tip,
      last_tip_hint,
      last_tip_type,
      last_tip_at,

      generated_at: new Date().toISOString()
    }
  }];

$('Webhook GET Endpoint für Overlay1').first().json.query.lead_id

// ===============================                                                                                                 
  // STORE LAST TIP (GLOBAL CACHE) - works for AI + Fastlane paths
  // ===============================                                                                                                 

  const staticData = $getWorkflowStaticData("global");
  const tipObj = $json || {};

  // Timestamp
  const timestamp = tipObj.generated_at || new Date().toISOString();

  // Try to read feedback guidance directly from node
  let fbNode = {};
  try {
    fbNode = $node["Build Feedback Guidance v"].json || {};
  } catch (_) {
    fbNode = {};
  }

  // References: immer exakt 3 Einträge
  let refs = Array.isArray(tipObj.references) ? tipObj.references.slice(0, 3) : [];
  refs = refs.map((r, i) => ({
    name: r?.name || r?.title || `Referenz ${i + 1}`,
    branche: r?.branche || r?.category || "",
    url: r?.url || r?.link || "",
    why: r?.why || r?.reason || ""
  }));
  while (refs.length < 3) refs.push({ name: "", branche: "", url: "", why: "" });

  // Evidence normalisieren
  let evidence = Array.isArray(tipObj.evidence) ? tipObj.evidence : [];
  evidence = evidence
    .filter((e) => e && typeof e === "object")
    .map((e) => ({
      source: ["pattern_node", "historical_deal", "session_fact"].includes(e.source) ? e.source : "historical_deal",
      id: String(e.id || "unknown"),
      why_relevant: String(e.why_relevant || "")
    }));

  const warnings = Array.isArray(tipObj.warnings)
    ? tipObj.warnings.map((w) => String(w))
    : [];

  // fallback tip_id, falls upstream fehlt
  const fallbackTipId = `tip_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;

  // Feedback Felder: Node-Priorität, dann tipObj
  const feedbackBest = fbNode.feedback_best_tip_type ?? tipObj.feedback_best_tip_type ?? null;
  const feedbackAvoid = fbNode.feedback_avoid_tip_type ?? tipObj.feedback_avoid_tip_type ?? null;
  const feedbackGuidance = fbNode.feedback_guidance ?? tipObj.feedback_guidance ?? "";
  const feedbackRowsUsed = Number.isFinite(Number(fbNode.feedback_rows_used))
    ? Number(fbNode.feedback_rows_used)
    : (Number.isFinite(Number(tipObj.feedback_rows_used)) ? Number(tipObj.feedback_rows_used) : 0);

  let feedbackScoredRaw = [];
  if (Array.isArray(fbNode.feedback_scored_types)) feedbackScoredRaw = fbNode.feedback_scored_types;
  else if (Array.isArray(tipObj.feedback_scored_types)) feedbackScoredRaw = tipObj.feedback_scored_types;

  const feedbackScored = feedbackScoredRaw
    .filter((x) => x && typeof x === "object")
    .map((x) => ({
