      score: Number.isFinite(Number(x.score)) ? Number(x.score) : 0,
      helpful: Number.isFinite(Number(x.helpful)) ? Number(x.helpful) : 0,
      harmful: Number.isFinite(Number(x.harmful)) ? Number(x.harmful) : 0,
