  // ---- STORE ----
  staticData.lastTipObj = {
    tip: tipObj.tip || "Kein Tipp...",
    tip_type: tipObj.tip_type || "general",
    confidence: (typeof tipObj.confidence === "number" ? Math.max(0, Math.min(1, tipObj.confidence)) : 0.5),
