    new_run: true,

    references: refs,

    reference_query: tipObj.reference_query || "",
    ref_context: tipObj.ref_context || "",

    talk_ratio_warning: !!tipObj.talk_ratio_warning,
    pacing_warning: !!tipObj.pacing_warning,

    current_wpm: tipObj.current_wpm ?? null,
