  const outcome_note = String(src.outcome_note ?? "").trim();
  const applied_by_rep = (typeof src.applied_by_rep === "boolean")
    ? src.applied_by_rep
    : (String(src.applied_by_rep ?? "").toLowerCase() === "true");

  if (!tip_id) throw new Error("tip_id is required");
  if (!allowed.includes(outcome_label)) {
    throw new Error("outcome_label must be one of: helpful|neutral|harmful|won");
  }

  return [{
    json: {
      tip_id,
      outcome_label,
      outcome_note,
      applied_by_rep,
      updated_at: new Date().toISOString()
    }
  }];

const j = $json || {};

  if (!j.id) {
