parameters.jsCode:
const rows = $input.all().map(i => i.json || {});
  if (!rows.length) {
    throw new Error("No existing tip_feedback row found for tip_id");
  }

  const p = $node["Validate Outcome Payload1"].json || {};

  function score(r) {
    let s = 0;
    if (r.session_id) s++;
    if (r.lead_id) s++;
    if (r.tip_type) s++;
    if (r.tip_text) s++;
    if (r.reasoning_mode) s++;
    if (r.confidence !== null && r.confidence !== undefined) s++;
    if (r.created_at) s++;
    return s;
  }

  rows.sort((a, b) => score(b) - score(a));

  const best = rows[0];

  return [{
    json: {
      id: best.id,
      tip_id: best.tip_id,
      outcome_label: p.outcome_label,
      outcome_note: p.outcome_note || "",
      applied_by_rep: !!p.applied_by_rep,
      updated_at: p.updated_at || new Date().toISOString()
    }
  }];

// Build Feedback Guidance v1 (robust)
  // Primary source: "Load Tip Feedback" node output
  // Fallback source: $json.prior_tip_feedback

  let items = [];
  try {
    items = ($items("Load Tip Feedback1") || []).map(i => i.json || {});
  } catch (_) {
    items = [];
  }

  if (!items.length) {
    items = Array.isArray($json.prior_tip_feedback) ? $json.prior_tip_feedback : [];
  }

  // Keep only usable rows
  items = items.filter(r => r && (r.tip_type || r.outcome_label));

  const byType = {};
  for (const r of items) {
    const t = String(r.tip_type || "general");
    if (!byType[t]) byType[t] = { helpful: 0, harmful: 0, won: 0, neutral: 0, total: 0 };

    const o = String(r.outcome_label || "neutral").toLowerCase();
    if (o === "helpful") byType[t].helpful++;
    else if (o === "harmful") byType[t].harmful++;
    else if (o === "won") byType[t].won++;
    else byType[t].neutral++;

    byType[t].total++;
  }

  const scored = Object.entries(byType)
    .map(([tip_type, s]) => {
      const score = (s.helpful * 1) + (s.won * 3) - (s.harmful * 2);
      return { tip_type, score, ...s };
    })
    .sort((a, b) => b.score - a.score);

  const bestRaw = scored[0] || null;
  const worstRaw = scored.length ? [...scored].sort((a, b) => a.score - b.score)[0] : null;

  // Guardrails: avoid overfitting to very small sample sizes
  const bestEligible = !!(
    bestRaw &&
    bestRaw.total >= 2 &&
    bestRaw.score > 0
  );

  const avoidEligible = !!(
    worstRaw &&
    (
      worstRaw.harmful >= 2 ||
      worstRaw.score <= -2
    )
  );

  const best = bestEligible ? bestRaw : null;
  const avoid = avoidEligible ? worstRaw : null;

  let feedback_guidance = "Keine verwertbare Feedback-Historie vorhanden.";

  if (scored.length > 0) {
    feedback_guidance = "Feedback vorhanden, aber noch zu wenig für harte Steuerung.";
  }

  if (best) {
    feedback_guidance =
      `Bevorzuge ${best.tip_type} (score=${best.score}, total=${best.total}, helpful=${best.helpful}, won=${best.won}).`;
  }

  if (avoid && (!best || avoid.tip_type !== best.tip_type)) {
    feedback_guidance +=
      ` Vermeide ${avoid.tip_type} (score=${avoid.score}, total=${avoid.total}, harmful=${avoid.harmful}).`;
  }

  // Optional diagnostics for prompt/debug
  const feedback_min_samples_for_best = 2;
  const feedback_min_harmful_for_avoid = 2;
  const feedback_min_negative_score_for_avoid = -2;

  return [{
    json: {
      feedback_scored_types: scored.slice(0, 6),
      feedback_best_tip_type: best ? best.tip_type : null,
      feedback_avoid_tip_type: avoid ? avoid.tip_type : null,
      feedback_guidance,
      feedback_rules: {
        min_samples_for_best: feedback_min_samples_for_best,
        min_harmful_for_avoid: feedback_min_harmful_for_avoid,
        min_negative_score_for_avoid: feedback_min_negative_score_for_avoid
      },
      feedback_source: items.length ? "load_tip_feedback" : "prior_tip_feedback",
      feedback_rows_used: items.length
    }
  }];

