  }

  return [{ json: out }];

// -----------------------------
 // Robust Parse + Referenzen normalisieren + deduplizieren (genau 3)
 // -----------------------------
 const item = $input.item.json || {};

 // Optional: manual_branche direkt aus Webhook-Query
 let manualBranche = "";
 try {
   manualBranche = String($node["Webhook GET Endpoint für Overlay1"].json.query.manual_branche || "").trim();
 } catch (_) {}

 // Hilfsfunktionen
 function str(v, d = "") {
   return v === null || v === undefined ? d : String(v).trim();
 }

 function tryParseJson(text) {
   if (!text) return null;
   try { return JSON.parse(text); } catch (_) {}

   const start = text.indexOf("{");
   const end = text.lastIndexOf("}");
   if (start >= 0 && end > start) {
     try { return JSON.parse(text.slice(start, end + 1)); } catch (_) {}
   }
   return null;
 }

 // 1) Output robust extrahieren
 // mögliche Formen:
 // - { output: { ... } }
 // - { output: "{...json...}" }
 // - { text: "{...json...}" }
 // - direkt { branche, referenzen, ... }
 let out = {};

 if (typeof item.output === "object" && item.output) {
   out = item.output;
 } else if (typeof item.output === "string") {
   out = tryParseJson(item.output) || {};
 } else if (typeof item.text === "string") {
   out = tryParseJson(item.text) || {};
 } else {
   out = item;
 }

 // falls verschachtelt unter output.output
 if (out && typeof out.output === "object" && out.output) {
   out = out.output;
 }

 // 2) Branche bestimmen (manual hat Vorrang)
 let branche = str(out.branche, "");
 if (manualBranche) branche = manualBranche;
 if (!branche) branche = "Diverses";

 // 3) Referenzen lesen (verschiedene Feldnamen akzeptieren)
 let refs = [];
 if (Array.isArray(out.referenzen)) refs = out.referenzen;
 else if (Array.isArray(out.references)) refs = out.references;
 else refs = [];

 // 4) normalisieren MIT DEN FELDNAMEN DIE DAS OVERLAY ERWARTET
 refs = refs.map((r, i) => ({
   name: str(r?.name || r?.titel || r?.title || `Referenz ${i + 1}`),
   branche: str(r?.branche || branche),
   link: str(r?.link || r?.url || ""),
   beschreibung: str(r?.beschreibung || r?.why || r?.description || "")
 }));

 // 5) dedup
 const seen = new Set();
 refs = refs.filter((r) => {
   const key = r.link
     ? `url:${r.link.toLowerCase()}`
     : `nb:${r.name.toLowerCase()}|${r.branche.toLowerCase()}`;
   if (seen.has(key)) return false;
   seen.add(key);
   return true;
 });

 // 6) exakt 3 Referenzen
 refs = refs.slice(0, 3);
 while (refs.length < 3) {
   refs.push({ name: "", branche: "", link: "", beschreibung: "" });
 }

 // 7) Erklärung mit Fallback
 const erklaerung = str(
   out.erklärung || out.erklaerung || out.why,
   manualBranche
     ? `Manuelle Branche '${manualBranche}' verwendet.`
     : "Keine zusätzliche Erklärung verfügbar."
 );

 // Rückgabe für Webhook
 return [{
   json: {
     references: refs,
     erklärung: erklaerung,
     branche
   }
 }];

// Parse Metadaten aus der AI-Antwort
const output = $input.item.json.output || '';

let cleanOutput = output;
let metadata = {
  lead_name: null,
  contact_name: null,
  city_tag: null,
  industry: null,
  avg_response_days: null
};

// Extrahiere META-Tag
const metaMatch = output.match(/\[META:\s*([^|\]]+)\|([^|\]]+)\|([^|\]]+)\|([^|\]]+)\|([^\]]+)\]/);

if (metaMatch) {
  metadata.lead_name = metaMatch[1]?.trim() || null;
  metadata.contact_name = metaMatch[2]?.trim() || null;
  metadata.city_tag = metaMatch[3]?.trim() || null;
  metadata.industry = metaMatch[4]?.trim() || null;

  const responseDays = parseFloat(metaMatch[5]?.trim());
  metadata.avg_response_days = !isNaN(responseDays) ? responseDays : null;

  // Entferne META-Tag aus der Antwort
  cleanOutput = output.replace(/\[META:[^\]]+\]/g, '').trim();
}

return [{
  json: {
    output: cleanOutput,
    lead_name: metadata.lead_name,
    contact_name: metadata.contact_name,
    city_tag: metadata.city_tag,
    industry: metadata.industry,
    avg_response_days: metadata.avg_response_days
  }
}];
